// Stonetop data — generated from Book I for the character creator + village sheet.
window.PBDATA = {"blessed":{"key":"blessed","name":"The Blessed","page":105,"maxHp":18,"damageDie":"d6","baseArmor":0,"statArray":[2,1,1,0,0,-1],"instincts":["Delight: To find beauty, in even the most ugly thing.","Detachment: To remain unmoved, to be cold as winter.","Nurture: To help others grow, learn, or improve.","Preservation: To protect the natural world.","Reverence: To demand sacrifice to the spirits and Danu."],"backgrounds":[{"name":"Initiate","desc":"You are an initiate of Stonetop's sacred order, keepers of the old ways and speakers for Danu, the most gifted in generations.","grants":"The Rites of the Land move. Plus 2-3 fellow initiates as followers (Enfys, Afon, Gwendyl, Olwin, Seren) via the Initiates of Danu insert."},{"name":"Raised by Wolves","desc":"You grew up in the wild; beasts were your siblings and the wind taught you language. The ways of humans remain strange to you.","grants":"The Trackless Step move and advantage when you Forage. Once per session, mark XP when your wild ways alienate someone."},{"name":"Vessel","desc":"A seed of Danu's power has taken root in your soul, haunting your dreams with symbols; you feel mystic power in plants, stones, and soil.","grants":"The Danu's Grasp move. When you would spend 1 Stock from your sacred pouch, you may lose 2d4 HP instead."}],"startingNote":"You start with Spirit Tongue and Call the Spirits (fixed), plus 1 move from your Background and 1 move of your choice.","moves":[{"name":"Spirit Tongue","gist":"You can speak with beasts and spirits, and may always ask the GM what spirits are active here and get an honest answer.","level":1,"starting":true},{"name":"Call the Spirits","gist":"Requires Spirit Tongue. Spend 1 Stock and perform a short rite to make the spirits of a place or object manifest and hear you out.","level":1,"starting":true},{"name":"Rites of the Land","gist":"Once per season, overseeing sacred rites holds 1 Favor (4 if you sacrifice 1 Surplus); spend Favor as Stock. Sacrifice the much-loved to clear a debility or aid Fortunes.","level":1,"starting":false},{"name":"Trackless Step","gist":"Moving through nature carefully, you make no sound, leave no trace, and ignore hindering terrain. Spend 1 Stock to mark up to level+INT others with the benefit.","level":1,"starting":false},{"name":"Danu's Grasp","gist":"Spend 1 Stock, roll +WIS to bind a spirit or perversion of nature: pick 1 (10+ both): restrained, or 2d4 ignore-armor damage. At 0 HP it's bound in rune-etched stone.","level":1,"starting":false},{"name":"Amulets & Talismans","gist":"Spend 1 Stock to craft a charm vs a named harm; roll +INT when they'd suffer it (10+ ignore, 7-9 half, 6- normal). One charm at a time, one use.","level":1,"starting":false},{"name":"Barkskin","gist":"While touching the earth you have 2 armor. Mark another with 1 Stock and they gain this benefit as long as the mark remains.","level":1,"starting":false},{"name":"Big Magic","gist":"Each time taken, choose an additional remarkable trait for your sacred pouch and increase your max Stock by 2.","level":1,"starting":false},{"name":"Borrow Power","gist":"Requires Spirit Tongue. A spirit/beast loans you a tag or move stored in place of 1 Stock; roll +WIS to use it (10+ keep it, 7-9 lose it).","level":1,"starting":false},{"name":"Healer's Arts","gist":"Someone who Recovers under your care heals extra HP equal to your WIS; spend 1 Stock to heal +5 HP and stabilize their wounds/injuries.","level":1,"starting":false},{"name":"Heed My Words","gist":"When you Persuade by talking sense or warning against foolishness, you have advantage.","level":1,"starting":false},{"name":"Improved Stat","gist":"Each time taken, increase one of your stats by 1 (to a max of +2).","level":1,"starting":false},{"name":"Into the Lion's Den","gist":"Approach a beast calmly showing no fear and it won't harm you (may still test your nerve); lay your hand gently on it and it calms to your touch.","level":1,"starting":false},{"name":"Lightning Rod","gist":"When you Defend while touching the earth, spend 1 Readiness to intercept a nearby magical attack and redirect it harmlessly into the ground.","level":1,"starting":false},{"name":"Veil","gist":"Spend 1 Stock to cloak yourself/another: a named type of being ignores you, or you appear as someone else. Under scrutiny roll +INT (10+ holds, 7-9 holds with complication).","level":1,"starting":false},{"name":"Wards & Bindings","gist":"Spend 1 Stock to mark a boundary affecting who/what you describe (words up to your level), repelling or trapping them; roll +INT when first tested for how well it holds.","level":1,"starting":false},{"name":"Wild Soul","gist":"Requires level 2+. Each time taken, gain a Ranger move you qualify for (not Improved Stat or Superior Stat).","level":1,"starting":false},{"name":"Nature's Wrath","gist":"Requires level 6+ and Danu's Grasp. Danu's Grasp gains the area tag and can affect any creature; a mortal at 0 HP is subdued or killed rather than bound.","level":6,"starting":false},{"name":"Potent Workings","gist":"Requires level 6+ and Amulets & Talismans. Crafting a charm, spend 1 extra Stock to name an additional harm, or have the charm keep its potency on a 10+.","level":6,"starting":false},{"name":"Shared Souls","gist":"Requires level 6+ and Into the Lion's Den. Mark a beast with 1 Stock to direct it and perceive through its senses at any distance; treat as a 3-Loyalty follower.","level":6,"starting":false},{"name":"Suck the Poison Out","gist":"Requires level 6+ and Healer's Arts. Spend 1 Stock, roll +WIS to draw out a malady (10+ remove & store/discard it; 7-9 remove it but pick a downside).","level":6,"starting":false},{"name":"Superior Stat","gist":"Requires level 6+. Increase one of your stats by +1 (to a max of +3).","level":6,"starting":false},{"name":"Voice of the Earth Mother","gist":"Requires level 6+ and Spirit Tongue. Speaking for Danu, natural beasts and wild spirits respect your authority; all but the most headstrong obey, even against instinct.","level":6,"starting":false}],"possessionsNote":"Sacred pouch (magical, holds Stock) is fixed. Pick 2 more:","possessions":[{"name":"Apiary","gist":"Beeswax, candles (close, area, lasts ~1 hr), honey, bee smokers, hats & veils, etc."},{"name":"Collected offerings","gist":"Has uses; expend a use to produce something valuable to a spirit of the wild. Restore 1 use each season."},{"name":"Goatherd","gist":"Milk, cheese, pelts, meat, blood, horn, wool, etc. Each season, 1 in 4 chance of a bezoar (swallow to cure poison)."},{"name":"Herb garden","gist":"Shears, mortars, herbs, seeds, remedies, mild poisons, spades. Each spring d4 uses of bendis root (reach, area, fumes repel perversions of nature)."},{"name":"Mastiffs","gist":"2-3 followers (alert, keen-nosed, fierce, overprotective); HP 6; Damage d6 (hand, grabby); Instinct to bark & threaten; Cost: affection."}],"resources":[{"key":"stock","name":"Stock","max":3,"note":"Magical reagents held in your sacred pouch, spent to fuel many Blessed moves."}],"followerInsert":{"type":"initiates","note":"Initiates of Danu (Initiate background only): track the 2-3 chosen fellow initiates as followers - Enfys (HP 6), Afon (HP 8, Armor 2), Gwendyl (HP 6), Olwin (HP 6, Armor 1), Seren (HP 3) - each with tags, Damage, Instinct, Moves, Cost, and Loyalty."}},"fox":{"key":"fox","name":"The Fox","page":109,"maxHp":16,"damageDie":"d8","baseArmor":0,"statArray":[2,1,1,0,0,-1],"instincts":["Conscience","Freedom","Comfort","Prestige","Trickery"],"backgrounds":[{"name":"The Natural","desc":"Grew up local and picked up every skill quickly; known for bending rules and being the one folks turn to when there's a problem to solve.","grants":"When you Seek Insight you may roll +INT instead of +WIS and add 'What opportunity does no one else see?' to the questions."},{"name":"A Life of Crime","desc":"New to Stonetop, leaving behind a colorful criminal past; the village has taken you in for an honest life.","grants":"Start with Burgle OR Light Fingers (your choice) as an extra move, plus burglar tools OR a hidden stash as an additional special possession."},{"name":"The Prodigal Returned","desc":"Left long ago to live by your wits, now returned a minor celebrity with friends scattered across the known world.","grants":"When you declare you know someone outside Stonetop who can help, name them and roll +CHA: 10+ they help; 7-9 they help but pick 1 complication; 6- GM picks 1+."}],"startingNote":"Start with Ambush OR Skill at Arms; Danger Sense OR Perceptive; and 1 move of your choice.","moves":[{"name":"Ambush","gist":"Drop on a nearby foe: deal damage, or roll +DEX to deal damage and pick 2 (10+) / 1 (7-9): +1d4 dmg, silence them, slip away, or create advantage.","level":1,"starting":true},{"name":"Skill at Arms","gist":"When you wield a weapon with speed and grace, roll +DEX to Clash instead of +STR.","level":1,"starting":true},{"name":"Danger Sense","gist":"Ask GM 'Is there an ambush or trap here?' If yes, roll +INT: 10+ ask both questions, 7-9 ask 1, gain advantage to act on it; 6- you know but no XP.","level":1,"starting":true},{"name":"Perceptive","gist":"When you Seek Insight, ask 1 additional question. Even on a 6- you can ask 1 question (though you may not like how you learn it).","level":1,"starting":true},{"name":"Burgle","gist":"Sneak alone into a dangerous place, roll +INT: 7+ you return and GM tells what you learned, then pick 2 (10+) / 1 (7-9); 6- trouble or MIA.","level":1,"starting":false},{"name":"Light Fingers","gist":"Sleight of hand on an unwary mark succeeds unseen. If watched, roll +DEX: 10+ succeed unseen; 7-9 succeed OR unseen (your choice).","level":1,"starting":false},{"name":"All in the Wrist","gist":"Any knife/dagger gets the thrown tag in your hands; you keep a few iron throwing blades (near) that take no inventory. Reset ammo on Outfit.","level":1,"starting":false},{"name":"Catlike","gist":"Carrying a light load and acting with care you move silently; hiding in shadow you stay unseen until you draw attention, move, or attack.","level":1,"starting":false},{"name":"Rapier Wit","gist":"Pierce an NPC's pride with a quip and they must: attack (+1d4 if hit, but gives you advantage), respond in kind, or fume and lose composure.","level":1,"starting":false},{"name":"Silver Tongued","gist":"Use words to avoid suspicion/trouble, roll +CHA: 10+ hold 3 Nerve, 7-9 hold 1. Spend Nerve 1-for-1 to move freely, withstand scrutiny, or redirect attention.","level":1,"starting":false},{"name":"Under Your Skin","gist":"When you engage an NPC in conversation, ask GM 1 and get an honest answer: what they expect you to do, what they hide, or what they want.","level":1,"starting":false},{"name":"Free Running","gist":"Carrying a light load and moving with speed and grace, gain advantage on any move to surmount or bypass a physical obstacle.","level":1,"starting":false},{"name":"Irresistible","gist":"Ask a person's player if they find you attractive (honest answer, usually yes). Persuade using your charms as leverage with advantage.","level":1,"starting":false},{"name":"Laugh at Danger","gist":"When about to roll +CON, make a joke about the adversity and roll +CHA instead.","level":1,"starting":false},{"name":"Parry & Riposte","gist":"Requires Skill at Arms. When you Defend with a quick weapon, spend 1 Readiness to both halve an attack's effects and strike back (your damage, disadvantage).","level":1,"starting":false},{"name":"Improved Stat","gist":"Each time taken, increase one stat by 1 (max +2).","level":1,"starting":false},{"name":"Dabbler","gist":"Requires level 2+. Each time taken, choose a Heavy, Marshal, Ranger, or Seeker move you qualify for (not Improved/Superior Stat).","level":1,"starting":false},{"name":"Battle Dancer","gist":"Requires level 6+ and Skill at Arms. On a 12+ rolling +DEX to Clash, deal your damage, avoid the enemy's attack, and overawe your foes.","level":6,"starting":false},{"name":"Cheap Shot","gist":"Requires level 6+ and Ambush. When you Ambush with a hand weapon, you have advantage on your damage roll.","level":6,"starting":false},{"name":"Eye on the Door","gist":"Requires level 6+. To get everyone out, name an escape route and roll +INT: 10+ you're gone; 7-9 stay or go, but going costs you something the GM names.","level":6,"starting":false},{"name":"Pants on Fire","gist":"Requires level 6+. Defy Danger, Persuade, or Interfere by being deceitful with advantage. You may decline to answer questions other moves grant.","level":6,"starting":false},{"name":"Second Intent","gist":"Requires level 6+, Parry & Riposte, and Ambush. When you Defend and Parry & Riposte, also pick 1 option from the Ambush list.","level":6,"starting":false},{"name":"Slippery","gist":"Requires level 6+. When you roll to escape being caught or controlled, treat a 6- as 7-9. On 12+ say how you turn the tables to your advantage.","level":6,"starting":false},{"name":"Superior Stat","gist":"Requires level 6+. Increase one of your stats by +1 (to a max of +3).","level":6,"starting":false}],"possessionsNote":"You always have a sacred pouch (holds Stock, no inventory space). Then Pick 2 of the following:","possessions":[{"name":"Burglar's kit","gist":"Picks, files, snippers, wire, prybars, hacksaws, a lantern (close area), a grappling hook, etc."},{"name":"Carpenter's tools","gist":"Chisels, files, nails, pitch, prybars, saws, firkins, barrels, etc."},{"name":"Distillery","gist":"Skins of fine whisky (limited uses, grants advantage to Persuade), copper tubes, malt, firkins, stills, barrels."},{"name":"Hidden stash","gist":"Limited uses; each use produces valuables worth a purse of silvers (Value 2)."},{"name":"Mummer's kit","gist":"Juggling balls, whirlybird seeds, motley, ribbons, bells, puppets, a fiddle, etc."},{"name":"Scribe's tools","gist":"Parchment, ink, pigments, vials, quills, a notebook, etc."},{"name":"Tannery (or access to it)","gist":"Lime, acid, salts, thick gloves, a boiled leather cuirass (1 armor), etc."},{"name":"Trade contacts","gist":"Small amounts of salt, glass, silk, spice, medicinal herbs, pigments, ivory, etc."}],"resources":[{"key":"stock","name":"Stock","max":3,"note":"Held in sacred pouch (herbs, powders, etc.). +1 per even level. Replenish in downtime; Forage to gain."},{"key":"nerve","name":"Nerve","max":3,"note":"From Silver Tongued; spend 1-for-1 to move freely, withstand scrutiny, or redirect attention."}],"followerInsert":{"type":"none","note":""}},"heavy":{"key":"heavy","name":"The Heavy","page":113,"maxHp":20,"damageDie":"d10","baseArmor":0,"statArray":[2,1,1,0,0,-1],"instincts":["Peace","Pride","Recklessness","Trouble","Violence"],"backgrounds":[{"name":"Sheriff","desc":"You keep order in Stonetop and protect it from outside threats; folk know you've a cool head and the weight to back your words.","grants":"Bark an order/warning, roll +CHA: on 7+ they must do as you say, dig in/flee, or attack you; on 10+ sense their choice and act first for advantage."},{"name":"Blood-Soaked Past","desc":"You left a life of violence and a name mothers used to scare children, yet Stonetop took you in as one of their own.","grants":"Persuade with violence/threats vs. those who know your reputation rolls +STR; Formidable can roll +CON; killing without mercy deals +1d4 damage."},{"name":"Storm-Marked","desc":"Touched by Tor, you bear runic markings like those etched in the Stone, mark of (or source of) your strength, speed, and courage.","grants":"Start with the Storm Markings major arcanum; mark a box on its sheet and describe surviving a lightning strike unharmed."}],"startingNote":"You start with Dangerous, Hard to Kill, and either Armored OR Uncanny Reflexes.","moves":[{"name":"Dangerous","gist":"When you deal your damage, you have advantage.","level":1,"starting":true},{"name":"Hard to Kill","gist":"At Death's Door, roll +CON or +nothing; on 7-9 mark a debility to regain 1 HP.","level":1,"starting":true},{"name":"Armored","gist":"Carrying a shield marks only 4; ignore cumbersome on worn armor. If taken at start, add a 2-armor warm cumbersome hauberk/cuirass/coat.","level":1,"starting":true},{"name":"Uncanny Reflexes","gist":"While unarmored on a normal/light load, impose disadvantage on any damage you could dodge or roll with.","level":1,"starting":true},{"name":"Battle Joy","gist":"When blood spills and you lose yourself in battle, ignore fear, pain, mind-control, and debilities while fighting; roll +CON when it stops.","level":1,"starting":false},{"name":"Berserker","gist":"Requires Battle Joy. In Battle Joy, your melee attacks gain the area tag, hitting all nearby (friend and foe); roll damage per target.","level":1,"starting":false},{"name":"Carved Out of Wood","gist":"Increase your max HP by 4.","level":1,"starting":false},{"name":"Formidable","gist":"Wading into battle, roll +CHA: 10+ both, 7-9 pick 1 (lesser foes quail/flee; doughty foes focus on you); 6- pick 1 and ask what you missed.","level":1,"starting":false},{"name":"Payback","gist":"Deal +1d4 damage to a foe that has harmed you or an ally.","level":1,"starting":false},{"name":"Relentless","gist":"When you Clash and your foe survives, gain advantage the next time you Clash with them.","level":1,"starting":false},{"name":"Seasoned Warrior","gist":"Requires level 2+. Take a qualifying move from the Fox, Marshal, Ranger, or Seeker (a different playbook each time); not Improved/Superior Stat.","level":1,"starting":false},{"name":"Situational Awareness","gist":"Seek Insight can ask: biggest threat, enemy's true position, what to use as a weapon. When a fight breaks out, ask the GM one such question.","level":1,"starting":false},{"name":"Unfettered","gist":"When subject to physical or mental restraint, mark a debility to immediately break free of it.","level":1,"starting":false},{"name":"Terror on the Field","gist":"Reduce a foe to 0 HP and describe taking them out; a brutal/impressive kill leaves their allies impressed, dismayed, or frightened.","level":1,"starting":false},{"name":"Frosty","gist":"Defy Danger by keeping calm: on 10+ also ask a Seek Insight question and gain advantage on your next move to act on the answer.","level":1,"starting":false},{"name":"Guardian","gist":"When you Defend, hold 1 extra Readiness; even on a 6- hold 1 Readiness (plus whatever the GM says).","level":1,"starting":false},{"name":"Improved Stat","gist":"Each time taken, increase one of your stats by 1 (max +2).","level":1,"starting":false},{"name":"Intimidating","gist":"When you Persuade using violence or threats, you have advantage.","level":1,"starting":false},{"name":"Musclebound","gist":"Requires Strength +2 or higher. Your hand-to-hand or thrown attacks are forceful and messy; if already so, even more so.","level":1,"starting":false},{"name":"Bringer of Ruin","gist":"Requires level 6+. On a 12+ to Clash where the foe survives, name a possession of theirs (not lethal); it is broken/shattered/lost.","level":6,"starting":false},{"name":"Cut From Granite","gist":"Requires level 6+ and Carved Out of Wood. Gain +1 armor (stacks) and +2 max HP more (+6 HP total).","level":6,"starting":false},{"name":"Mighty Thews","gist":"Requires level 6+ and Musclebound. Pull off feats of extraordinary strength, but pick 1: takes a while, causes unwanted harm, or takes a toll.","level":6,"starting":false},{"name":"Nemesis","gist":"Requires level 6+ and Relentless. When you Clash and your foe survives, all your future attacks against them do +1d6 damage.","level":6,"starting":false},{"name":"Steadfast Guardian","gist":"Requires level 6+ and Guardian. While holding Readiness from Defend, suffer an attack's damage/effects for your ward without spending Readiness.","level":6,"starting":false},{"name":"Stone Cold","gist":"Requires level 6+ and Frosty. When you Defy Danger (or Struggle as One) by keeping calm and carrying on, treat a 6- as a 7-9.","level":6,"starting":false},{"name":"Superior Stat","gist":"Requires level 6+. Increase one of your stats by +1 (max +3).","level":6,"starting":false},{"name":"Unstoppable","gist":"Requires Hard to Kill. Keep fighting at 0 HP, marking 1 per hit (clear a mark instead of regaining HP); roll Death's Door at -1 per mark when you stop.","level":1,"starting":false}],"possessionsNote":"Pick 2:","possessions":[{"name":"Distillery","gist":"Skins of fine whisky (limited uses, grant advantage to Persuade), copper tubes, malt, firkins, stills, barrels, etc."},{"name":"Chirurgeon's tools","gist":"Catgut, straps, bandages, tubes, poultices, willow bark, bonesaws, etc."},{"name":"Husbandry tools","gist":"Brushes, muzzles, collars, feed, whips, bridles, etc. Gain advantage to Persuade domestic beasts (livestock, dogs, etc.)."},{"name":"Smithy (or access to it)","gist":"Iron goods, ingots, thick gloves, tongs, bellows, an anvil, etc."},{"name":"Stoneworker's tools","gist":"Chisels, drills, prybars, spikes, block & tackles, wheelbarrow, etc."},{"name":"Weapons of war","gist":"Choose up to 3 (now or later): Sword (+1 dmg); Battleaxe (messy); Warhammer (2 piercing); Mace/flail (forceful); Crossbow (far, +1 dmg, reload, piercing, low ammo)."}],"resources":[],"followerInsert":{"type":"none","note":""}},"judge":{"key":"judge","name":"The Judge","page":117,"maxHp":20,"damageDie":"d6","baseArmor":0,"statArray":[2,1,1,0,0,-1],"instincts":["Ambition (to increase your status or influence)","Dispassion (to disregard emotion or sentiment)","Harmony (to seek a path that makes everyone happy)","Orthodoxy (to strictly adhere to rules and traditions)","Zeal (to judge quickly and without doubt)"],"backgrounds":[{"name":"Legacy","desc":"Latest in a long line of Judges, born here and apprenticed to the prior Judge. The Chronicle is a rich but unindexed repository of lore.","grants":"Advantage to Know Things about Stonetop's people or history. Spend days/weeks/months poring over the Chronicle to ask the GM a question and learn the answer."},{"name":"Missionary","desc":"Part of a larger order of Judges sent to protect civilization; the Chronicle is new and your standing uncertain. Add 2 more order Judges to the steading's Neighbors.","grants":"When you call on another steading's Judge for aid or info they are oathbound to give it (and you to support them). You also gain an aviary in addition to your usual special possession; send messages via trained bird."},{"name":"Prophet","desc":"The line of Judges was broken and the Chronicle lost; Aratis called you personally through dreams, omens, and visions. Some in town resent your assumed authority.","grants":"Spend a few days communing with Aratis about a threat, roll +WIS: 7+ she reveals her desired course of action; 10+ also hold 2 Sanction. Spend 1 Sanction while on her orders to add +1 to a roll just made."}],"startingNote":"You start with Censure, Chronicler of Stonetop, plus 2 more moves of your choice.","moves":[{"name":"Censure","gist":"First time you denounce someone present as an agent of chaos, they pick 1: ashamed, doubtful, afraid, or enraged (next roll vs them has advantage).","level":1,"starting":true},{"name":"Chronicler of Stonetop","gist":"Write up and share detailed session notes to hold +1 Diligence; spend 1 Diligence anytime to add +1 to a roll you or a fellow player just made.","level":1,"starting":true},{"name":"Aegis of Faith","gist":"A shield you wield can turn away spells, magical effects, and insubstantial attacks as if they were physical blows.","level":1,"starting":false},{"name":"Armored","gist":"Carrying a shield, mark only 4 armor instead of 4/4; ignore cumbersome on worn armor. If taken at start, add an iron hauberk, bronze cuirass, or scale coat.","level":1,"starting":false},{"name":"Bear Witness","gist":"When you speak the truth with conviction and candor, none can doubt you; they may deny it but in their hearts they recognize the truth.","level":1,"starting":false},{"name":"Break Bread","gist":"Share a proper meal where each of you eats their fill, and each of you recovers 1d8 extra HP.","level":1,"starting":false},{"name":"Bulwark","gist":"When you Defend, spend 1 Readiness to stand fast, holding your position despite what befalls you.","level":1,"starting":false},{"name":"Castigate","gist":"Requires Censure (level 2+). When you Censure someone, your voice deals 1d4 damage to them (near, loud, ignores armor).","level":1,"starting":false},{"name":"The Hammer and the Book","gist":"Strike a thing of supernatural chaos, roll +WIS: 10+ deal damage and choose 1 (+1d6 dmg / ignore armor / suppress a power / force from host); 7-9 same but expose yourself.","level":1,"starting":false},{"name":"Truth or Consequences","gist":"Gaze on someone's soul to ask if they're lying or hiding something; honest answer, and a Yes grants advantage on your next roll vs them. Deceiving with words gives you disadvantage on your next roll vs that person.","level":1,"starting":false},{"name":"Binding Arbitration","gist":"Requires Truth or Consequences. Witness an oath/promise, then anytime ask if they kept their word (honest answer, even if absent); if broken you gain advantage on all rolls vs them until they admit it and suffer a consequence.","level":1,"starting":false},{"name":"Vision Unclouded","gist":"When you Seek Insight, you can always ask 'What here is hidden by illusion or magic?' for free, even on a 6-.","level":1,"starting":false},{"name":"Well-Read","gist":"When you name the source you read about the matter in, roll +WIS to Know Things instead of +INT.","level":1,"starting":false},{"name":"For the Greater Good","gist":"When you Persuade someone to act in defense of their community or civilization at large, you have advantage.","level":1,"starting":false},{"name":"Hound of Aratis","gist":"When you Seek Insight, you can always ask 'What here is tainted by chaos?' for free, even on a 6-.","level":1,"starting":false},{"name":"Like a Dog with a Bone","gist":"Requires Hound of Aratis. When you attack something you know to be tainted by chaos, deal +1d6 damage.","level":1,"starting":false},{"name":"Knowledge is Power","gist":"When you roll 10+ to Know Things, you or an ally gain advantage on the next roll to act on what you learn.","level":1,"starting":false},{"name":"Many Hands Make Light Work","gist":"Jump in to help another character who just rolled; tell how and ask the GM the cost/requirement. If you accept, increase your ally's roll by +1.","level":1,"starting":false},{"name":"A Bundle of Sticks Unbroken","gist":"Requires Many Hands Make Light Work. When you Struggle as One, you and one ally of your choice have advantage.","level":1,"starting":false},{"name":"Improved Stat","gist":"Each time you take this move, increase one of your stats by 1 (to a max of +2).","level":1,"starting":false},{"name":"A Mighty Rampart","gist":"Requires level 6+; replaces Bulwark. While holding Readiness from Defend you can't be forced from your position, and can spend 1 Readiness to wholly ignore an attack's effects/damage.","level":6,"starting":false},{"name":"Armistice","gist":"Requires level 6+ and Bear Witness. Approach an enemy to negotiate in good faith and they'll at least hear you out; even debased foes delay violence until you've spoken.","level":6,"starting":false},{"name":"Condemn","gist":"Requires level 6+ and Censure. When you Censure someone they're marked with an unremovable mystical brand; any intelligent creature recognizes the bearer as an agent of chaos.","level":6,"starting":false},{"name":"Proclamation","gist":"Requires level 6+ and Condemn. When you Censure, denounce a clearly identifiable group/faction, applying Censure's effects to every member regardless of distance.","level":6,"starting":false},{"name":"Mirrorshield","gist":"Requires level 6+ and Aegis of Faith. When you Defend with a shield, spend 1 Readiness to intercept a magical force and redirect it to a different target (or none).","level":6,"starting":false},{"name":"Superior Stat","gist":"Requires level 6+. Increase one of your stats by +1 (to a max of +3).","level":6,"starting":false},{"name":"The Tower Eternal","gist":"Requires level 6+. When you Defy Danger against magic, treat a result of 6- as a 7-9.","level":6,"starting":false}],"possessionsNote":"Your symbol of authority (pick 1) + scribe's tools, then pick 1 more:","possessions":[{"name":"Symbol of authority: Black iron maul","gist":"Utterly immune to all magic (close, forceful, awkward, +1 damage)."},{"name":"Symbol of authority: Makerglass shield","gist":"Etched with Aratis's symbol; indestructible, +1 armor, +1 Readiness on a Defend 7+."},{"name":"Symbol of authority: Dark-ice Helm","gist":"Helm set with a dark ice 'jewel'; grants advantage to resist mind-affecting magic."},{"name":"Scribe's tools (fixed)","gist":"Parchment, ink, pigments, vials, quills, a notebook, etc."},{"name":"Aviary","gist":"Thick gloves, bird hoods, tethers, seed, messenger birds, birdcages, etc."},{"name":"Carpenter's tools","gist":"Chisels, files, nails, pitch, prybars, saws, firkins, barrels, etc."},{"name":"Engineer's tools","gist":"Rulers, tapes, rods, plumb-bobs, tripods, block & tackles, wheelbarrow, etc."},{"name":"Smithy (or access to it)","gist":"Iron goods, ingots, thick gloves, tongs, bellows, an anvil, etc."}],"resources":[{"key":"diligence","name":"Diligence","max":3,"note":"From Chronicler of Stonetop; spend 1 to add +1 to a roll you or a fellow player just made."},{"key":"sanction","name":"Sanction","max":2,"note":"Prophet background only; gained on a 10+ communing with Aratis. Spend 1 to add +1 to a roll on her orders."}],"followerInsert":{"type":"none","note":""}},"lightbearer":{"key":"lightbearer","name":"The Lightbearer","page":121,"maxHp":18,"damageDie":"d4","baseArmor":0,"statArray":[2,1,1,0,0,-1],"instincts":["Charity: To go without so that others are better off.","Hope: To inspire others in the face of adversity.","Mercy: To bring relief or comfort, to give second chances.","Praise: To spread the glory and worship of Helior.","Righteousness: To refuse to suffer an injustice or a lesser evil."],"backgrounds":[{"name":"Auspicious Birth","desc":"Born in Stonetop, your birth marked by the God of Light (an eclipse, a new star, a sun-shaped birthmark). A place of honor, though you unsettle some.","grants":"When a move has you mark a debility, you may mark this background's circle instead, to no ill effect. Clear it when you Make Camp or Convalesce."},{"name":"Itinerant Mystic","desc":"A self-important kook who passes through now and again, speaking in riddles and playing with light. Folks sense something holy, but you're no proper priest.","grants":"Hold Enigma when you go a-wandering (1 days / 2 weeks / 3 months); hold 3 at start of play. Spend Enigma 1-for-1 to return exactly when/where needed fully Outfitted, Know Things as a 10+, or Have What You Need (Value 1 or less)."},{"name":"Soul on Fire","desc":"You once led a worldly life of fear, doubt, and petty grudges until a brush with death or profound misery. There, Helior's light ignited in your soul and filled you with purpose.","grants":"When you Persuade a group by preaching charity, mercy, and hope and roll 7+, also choose 1: your name and message spread; OR someone approaches you, now or later, eager to know more."}],"startingNote":"You start with Consecrated Flame and Invoke the Sun God, plus 1 more move of your choice.","moves":[{"name":"Consecrated Flame","gist":"Whisper words of consecration to a flame and it casts holy light, uncomfortable for creatures of darkness but harmless. Lasts until the flame goes out or you consecrate another.","level":1,"starting":true},{"name":"Invoke the Sun God","gist":"Imbue a holy light with Helior's power; choose a known Invocation and roll +WIS. 10+ it works but choose 1 consequence; 7-9 it works but you and GM each choose 1 (reduced effect, mark debility, light snuffed out, or must bask in sunlight before reusing).","level":1,"starting":true},{"name":"A Candle Against the Dark","gist":"When you wield a holy light but go otherwise unarmed, you have 2 Armor.","level":1,"starting":false},{"name":"Luminous Shield","gist":"(Requires A Candle Against the Dark) Brandish a holy light to turn aside an attack on body, mind, or soul; roll +CHA. 10+ deflected and attacker in range is briefly blinded; 7-9 deflected but your light flickers and dims; 6- light snuffs out, attack unimpeded.","level":1,"starting":false},{"name":"All Is Illuminated","gist":"Look closely on another to see their soul laid bare; roll +WIS. 10+ ask 1 listed question plus 'what would make them feel loved, beautiful, or worthy?'; 7-9 ask 1 listed question. They must answer truthfully.","level":1,"starting":false},{"name":"And Behold a Pale Horse","gist":"Spend the night gazing into a flame; ask the GM to reveal an impending doom or grim portent that will come to pass unless you intervene, and how you might yet do so.","level":1,"starting":false},{"name":"Keep the Home-Fires Burning","gist":"Build a camp fire and sprinkle it with ash from your own hearth; anyone who Makes Camp with you is free from nightmares/bad dreams and recovers extra HP equal to your CHA.","level":1,"starting":false},{"name":"Lamplighter","gist":"When you whisper to a flammable object (torch, wick, kindling, etc.), it ignites in moments.","level":1,"starting":false},{"name":"Piety","gist":"Spend at least an hour in proper worship to Helior to hold 1 Blessing (other faithful PCs who partake also hold 1). Spend 1 Blessing anytime to add +1 to a roll you just made in pursuit of a righteous cause.","level":1,"starting":false},{"name":"Purifying Flames","gist":"When you wield a holy light against a creature of darkness, it counts as a weapon (d10 damage, hand, close, area, 2 piercing) and you can choose to roll +WIS to Clash.","level":1,"starting":false},{"name":"Radiant Countenance","gist":"Give someone your fond attention, then Persuade them with advantage. If they're a follower, you can instead Strengthen Your Bond (as if you paid their cost).","level":1,"starting":false},{"name":"Rise Like the Sun","gist":"Draw attention to yourself by word or deed; roll +CHA. 10+ everyone turns and looks, and you hold their gaze as long as you keep giving them reason; 7-9 everyone turns and looks.","level":1,"starting":false},{"name":"Spring's First Thaw","gist":"Spend an hour or more seeking to stir hope, kindness, or mercy in an NPC; roll +CHA. 10+ lasting change; 7-9 kindle goodness for now but they revert; 6- their heart hardens and you can't use this on them again.","level":1,"starting":false},{"name":"Fire Within","gist":"In darkness, you see by the light of your inner fire. When you take cold or fire damage, reduce that damage by 2.","level":1,"starting":false},{"name":"Guiding Light","gist":"Lead one or more NPCs through danger; roll +CHA. 10+ you all make it through; 7-9 the GM tells you what's required to get everyone through safely.","level":1,"starting":false},{"name":"Helior's Unblinking Eye","gist":"Stare into the sun long enough to lose your vision, name a known person or place, roll +WIS. 10+ glimpse subject as from a great height, choose 2; 7-9 choose 1: glimpse lasts as long as you wish / POV shifts to very close range / you recover vision quickly.","level":1,"starting":false},{"name":"Improved Stat","gist":"Each time you take this move, increase one of your stats by 1 (to a max of +2).","level":1,"starting":false},{"name":"Burn Twice as Bright","gist":"(Requires level 6+ and Invoke the Sun God) When you Invoke the Sun God, you may mark a debility to use 2 Invocations at once. Roll once, and apply any consequences to both.","level":6,"starting":false},{"name":"Empowered Invocations","gist":"(Requires level 6+ and Invoke the Sun God) When you Invoke the Sun God, you can choose an extra consequence before you roll. If you do, the Invocation has its empowered effect.","level":6,"starting":false},{"name":"Glorious Servant","gist":"(Requires level 6+ and Invoke the Sun God) When you Invoke the Sun God and roll 10+, you need not choose a consequence; on a 7-9, you choose a consequence but the GM does not.","level":6,"starting":false},{"name":"Hungry Flames","gist":"(Requires level 6+ and Purifying Flames) When you deal damage with a holy light, you deal +1d6 damage and your target is engulfed in holy light and flames.","level":6,"starting":false},{"name":"Light, More Light","gist":"(Requires level 6+ and Consecrated Flame) Consecrated flames burn brighter: rushlight/candle reaches range, oil lamp/lantern/torch out to near, bullseye lantern out to far range.","level":6,"starting":false},{"name":"Superior Stat","gist":"(Requires level 6+) Increase one of your stats by +1 (to a max of +3).","level":6,"starting":false},{"name":"Wielder of the White Flame","gist":"(Requires level 6+ and Invoke the Sun God) Channel Helior's essence into an object; roll +WIS. 10+ it ignites with white holy light (reach, area), burns neither you nor it, and you may Invoke the Sun God now as a 10+; 7-9 it ignites with white holy light, burning neither.","level":6,"starting":false}],"possessionsNote":"Pick 2:","possessions":[{"name":"Apiary","gist":"Beeswax, candles (close, area, lasts ~1 hr), honey, bee smokers, hats & veils, etc."},{"name":"Books & scrolls (_ uses)","gist":"Expend a use to consult your collection and turn a Know Things roll you just made into a 10+."},{"name":"Chandlery","gist":"Beeswax, candles (close, area, lasts ~1 hr), wicks, scented herbs, soap, lye, ash, etc."},{"name":"Distillery (_ uses)","gist":"Skins of fine whisky (grants advantage to Persuade), copper tubes, malt, firkins, stills, barrels, etc."},{"name":"Glassworks","gist":"Vials, charms, lenses, sand, marbles, bellows, crucible, lanterns (_ hours, close, area), etc."},{"name":"Holy relics (_ uses)","gist":"If you have one in inventory when you Invoke the Sun God, you can mark a use in lieu of choosing a consequence."},{"name":"Luthier's tools","gist":"Chisels, files, catgut, various woods, stains, a lute, a fiddle, etc."},{"name":"_ (discuss with GM)","gist":"An additional possession of your own, worked out with the GM."}],"resources":[{"key":"enigma","name":"Enigma","max":3,"note":"Itinerant Mystic background. Held from wandering; spend 1-for-1 for boons."},{"key":"blessing","name":"Blessing","max":0,"note":"Piety move. Hold 1 per hour of worship; spend 1 for +1 to a righteous roll."}],"invocations":[{"name":"Bath of Healing Light","gist":"Focus your cupped light; patient picks 2: regains 5 HP (twice), clears a debility (twice), stabilize a problematic wound, or recover from a minor condition. Reduced: pick 1. Empowered adds 10 HP, full wound recovery, or cure dire affliction/poison/disease."},{"name":"Blinding Light (ongoing)","gist":"Your light blazes; any in range looking at it are temporarily blinded, others must avert their eyes; you're unaffected. Reduced: flares only a moment. Empowered: allies unaffected if you wish."},{"name":"Cleansing Light","gist":"Light flares, dispelling magical effects within range; potent lasting magics are merely suppressed and return once removed. Reduced: lasting magics unaffected, others suppressed. Empowered: ongoing, dispelling/suppressing magic entering range."},{"name":"Cold Light of Day (ongoing)","gist":"All in your light appears as it really is, without illusion, shapeshifting, or disguise. Reduced: lasts only a few moments. Empowered: illusions are dispelled and shapeshifters momentarily stunned."},{"name":"Dancing Light (ongoing)","gist":"Your light takes to the air, floating untethered from its fuel; move it anywhere you can see, even change shape or color. Reduced: dims, range down one step. Empowered: use another Invocation through it."},{"name":"Go Back to the Shadow","gist":"Spirits of darkness in your light take 2d8 damage (ignores armor), rolled separately; one reduced to 0 HP is banished or sent back to its tether. Reduced: 1d8. Empowered: utterly destroyed OR banished with its tether destroyed (GM's choice)."},{"name":"Hold Back the Darkness (ongoing)","gist":"Spirits and creatures of darkness are repelled and can't approach; cowardly/mindless flee; those forced into range deal damage with disadvantage. Reduced: needs unbroken litany. Empowered: forced entities are vulnerable to mundane weapons."},{"name":"Moth to a Flame (ongoing)","gist":"Name an individual or type of mortal creature; they gaze raptly and follow your light slowly. Ends if they take damage. Reduced: brief OR only some affected. Empowered: continues briefly after first damage; second damage ends it."},{"name":"Terrible as the Dawn (ongoing)","gist":"Name an individual or type of mortal creature; your light fills them with dread, causing them to recoil and back away; the cowardly flee. Reduced: all mortals but you are affected, including allies. Empowered: even the brave must cower or flee."},{"name":"Warmth of the Sun (ongoing)","gist":"While in your light, you and your allies are free of fear and doubt and unharmed by extreme cold. Reduced: only one person is protected. Empowered: also protects from necromantic and life-draining effects."}],"followerInsert":{"type":"none","note":""}},"marshal":{"key":"marshal","name":"The Marshal","page":125,"maxHp":20,"damageDie":"d8","baseArmor":0,"statArray":[2,1,1,0,0,-1],"instincts":["Authority: to take charge and throw your weight around","Caution: to keep everyone safe, to agonize over decisions","Drive: to take on ever more responsibility","Honor: to keep your word, to follow a moral code","Ruthlessness: to do whatever it takes to win or survive"],"backgrounds":[{"name":"Scion","desc":"Descended from a long line; some of Stonetop's biggest names are in your family tree. Everyone takes your authority as a given; your crew is a well-established institution.","grants":"Start with the Veteran Crew move (mark it now). Your Crew automatically gains the 'respected' tag (plus usual picks and any from Veteran Crew)."},{"name":"Penitent","desc":"You once led a band of ne'er-do-wells (bandits, raiders, mercenaries), but a moment of truth led you and some followers to leave that life; Stonetop took you in.","grants":"When you draw on your bloody past to Know Things, you may roll +STR instead of +INT (GM asks who you wronged). Your Crew automatically gains the 'warriors' tag (plus usual picks)."},{"name":"Luminary","desc":"A natural leader whose words inspire and whose deeds are recounted far and wide. Touched by the gods, of ancient blood, or simply the champion Stonetop needs.","grants":"Start with the We Happy Few move (mark it now). Your Crew automatically gains the 'devoted' tag (plus usual picks)."}],"startingNote":"Start with Crew, Logistics, any moves from your Background, and 1 move of your choice.","moves":[{"name":"Crew","gist":"You have a crew of stalwarts, about six residents of Stonetop with some steel; treat them as a follower with the group tag (see Crew insert).","level":1,"starting":true},{"name":"Logistics","gist":"When you have a steading Muster or Pull Together, or when you Requisition, you have advantage.","level":1,"starting":true},{"name":"Veteran Crew","gist":"Requires Crew. Each time taken, pick 1: select 2 new tags; increase damage die d6 to d8; or +2 max HP each. May also reselect Instinct and Cost.","level":1,"starting":false},{"name":"We Happy Few","gist":"Inspiring speech before a dire threat, roll +CHA: 10+ allies hold 2 Inspiration; 7-9 hold 1; 6- hold 1 but you take disadvantage until you share doubts. Spend 1-for-1 to act fearlessly, keep 1 HP, or +1d6 damage.","level":1,"starting":false},{"name":"Front Line Leader","gist":"When you lead your crew into battle, hold 2 Presence. Spend it in lieu of crew Loyalty or as Readiness (as if you Defended them).","level":1,"starting":false},{"name":"Stentorian","gist":"Your voice carries far. Going into battle, hold 2 Command. Spend 1 to shout an order/warning and pick 1: PCs get advantage on next roll to comply; or you have advantage to Order Followers or Deploy.","level":1,"starting":false},{"name":"Take the Measure","gist":"Size someone up: ask their player one question (trust, intent, useful/dangerous, exploitable weakness) for an honest answer; if they fear/respect you, ask another. Can't reuse until relationship shifts.","level":1,"starting":false},{"name":"Speak Softly","gist":"When you offer peace but your enemy refuses, gain advantage on your next roll against them.","level":1,"starting":false},{"name":"Shake It Off","gist":"Order an ally to overcome fear, pain, doubt, or delusion, roll +CHA: 10+ they do it; 7-9 a PC gets advantage, an NPC does it but needs time, resents you, or feels humiliated (GM's call).","level":1,"starting":false},{"name":"Shield Wall","gist":"Have your crew form a shield wall: they Defend with advantage and on a 7+ hold +2 Readiness. While in formation they can go on the offensive without losing Readiness.","level":1,"starting":false},{"name":"Read the Land","gist":"First moment surveying terrain, ask GM one (best way in/out/through; trap/ambush spot; most defensible position; what's out of place); gain advantage on your next roll to act on the answer.","level":1,"starting":false},{"name":"Prepare a Welcome","gist":"Requires Read the Land. Have allies fortify and lie in wait: hold 1 Surprise if rushed, 2 if you take your time. Spend 1 to reveal a ploy, roll +INT: 10+ it works and regain 1 Surprise; 7-9 it works.","level":1,"starting":false},{"name":"Set-Up Strike","gist":"When you Clash and get 7+, you may deal damage with disadvantage to instead create an opening for an ally to act on, as if you provided Aid.","level":1,"starting":false},{"name":"Sir, Permission to Die, Sir","gist":"When a follower would die, spend 1 of their Loyalty to have them survive (out of action but alive). If you let them go instead, mark XP.","level":1,"starting":false},{"name":"Armored","gist":"Carrying a shield, mark only 4 (instead of 4-4); ignore the cumbersome tag on worn armor. If taken at start, add an iron hauberk, bronze cuirass, or scale coat (2 armor, warm, cumbersome).","level":1,"starting":false},{"name":"Improved Stat","gist":"Each time taken, increase one of your stats by 1 (to a max of +2).","level":1,"starting":false},{"name":"Arts of War","gist":"Requires level 2+. Take a move from the Fox, Heavy, Judge, Ranger, or Seeker playbooks for which you qualify (different playbook each time). Can't take Improved or Superior Stat.","level":1,"starting":false},{"name":"Battlefield Grace","gist":"Requires Front Line Leader. When you take damage while leading your allies in battle, the damage roll has disadvantage.","level":6,"starting":false},{"name":"Heroes to the Last","gist":"Requires Veteran Crew. Each time taken, pick 1: they are exceptional (roll +2 not +1); inured to terror & horror; +4 max HP each; or increase damage die one size (max d10).","level":6,"starting":false},{"name":"Focus Fire","gist":"Requires Stentorian. Spend 1 Command to order allies to bring down a foe; each ally has advantage on their next damage roll against that foe.","level":6,"starting":false},{"name":"Like an Open Book","gist":"Requires Take the Measure. When you Take the Measure of someone who fears or respects you, your second question can be anything; GM may ask how you know.","level":6,"starting":false},{"name":"Noble Mien","gist":"When you lead an NPC through danger and return them to safety, if not in your crew they will either offer to join it or pledge future aid and support.","level":6,"starting":false},{"name":"Peace Through Strength","gist":"Requires Speak Softly. When you stand ready to fight alongside like-minded allies, anything capable of fear recognizes you as a serious threat and treats you accordingly.","level":6,"starting":false},{"name":"Superior Stat","gist":"Requires level 6+. Increase one of your stats by +1 (to a max of +3).","level":6,"starting":false}],"possessionsNote":"Pick 2:","possessions":[{"name":"Chirurgeon's tools","gist":"Catgut, straps, bandages, tubes, poultice, willow bark, bonesaws, etc."},{"name":"Distillery","gist":"Skins of fine whisky (uses; grants advantage to Persuade), copper tubes, malt, firkins, stills, barrels, etc."},{"name":"Engineer's tools","gist":"Rulers, tapes, rods, plumb-bobs, tripods, block & tackles, wheelbarrow, etc."},{"name":"Personal symbol","gist":"A flag, crest, marking, etc.; when displayed dramatically, your crew holds +1 Loyalty (max 3)."},{"name":"Scribe's tools","gist":"Parchment, ink, pigments, vials, quills, a notebook, etc."},{"name":"Weapons of war","gist":"Choose up to 3 (now or later): Sword, iron (close, +1 dmg); Long spear, fine steel (reach, 2 piercing); Battleaxe, iron (close, messy); Composite bow (far, +1 dmg, piercing; low ammo, all out)."}],"resources":[{"key":"presence","name":"Presence","max":2,"note":"From Front Line Leader; held when leading crew into battle."},{"key":"command","name":"Command","max":2,"note":"From Stentorian; held when going into battle, spent to shout orders."}],"followerInsert":{"type":"crew","note":"Tracks the Marshal's half-dozen-strong Crew as one group follower: shared HP (starts 6 ea), Armor (0), Damage (d6); Tags (group + background tag + 2 more); Instinct; Cost (with Loyalty track, max 3); and named standout Individuals each given a name, tag, and traits. Order Followers and Strengthen Your Bond govern use."}},"ranger":{"key":"ranger","name":"The Ranger","page":129,"maxHp":18,"damageDie":"d8","baseArmor":0,"statArray":[2,1,1,0,0,-1],"instincts":["Adventure: to test yourself, to experience new things.","Independence: to refuse help and push others away.","Stewardship: to value beasts and natural places over people.","Tenacity: to be stubborn, to persist.","Wonder: to marvel at beauty, magnificence, splendor."],"backgrounds":[{"name":"Mighty Hunter","desc":"A hunter of the Great Wood, the best the town has seen in generations; you know every part of the Wood within a two-day march.","grants":"Start with both the Expert Tracker move and the Stalker move."},{"name":"Wide Wanderer","desc":"You've travelled much of the known world and perhaps beyond. Add Ennis, Shahar, Yannic, Tovia, and Sasca to the Neighbors list (1 trait each).","grants":"Start with Mental Map. Know Things about the wider world with +WIS instead of +INT. On arriving somewhere visited before, the GM tells you how it changed."},{"name":"Beast-Bonded","desc":"Raised civilized, but your soul is bound to a wild beast you're closer to than any person.","grants":"Start with Animal Companion. Focus on it to use 1 marked action at any distance; mark 1 action at 1st, then 3rd/5th/7th/9th (gauge distance, call back, sense emotion, sense impression, lend strength)."}],"startingNote":"You start with Home on the Range, any moves from your Background, plus 1 move of your choice.","moves":[{"name":"Home on the Range","gist":"When a journey requires you to Defy Danger or Struggle as One, treat a 6- as a 7-9.","level":1,"starting":true},{"name":"Expert Tracker","gist":"When you Seek Insight from creature signs, ask 'What happened here recently?' free even on 6-. Tracking a trail, roll +WIS: 7+ follow to a significant change; 10+ also ask a question about your quarry.","level":1,"starting":false},{"name":"Stalker","gist":"Moving carefully under a normal/light load, you make no noise and leave no sign. Hidden in a natural environment, you stay unseen until you draw attention, move, or attack.","level":1,"starting":false},{"name":"Mental Map","gist":"You can always retrace your steps and gauge distances/directions; you can always find your way back. Recall a place to Seek Insight retroactively, as if still there.","level":1,"starting":false},{"name":"Animal Companion","gist":"You're accompanied by a beast of uncommon loyalty and cleverness. See the Animal Companion insert for details.","level":1,"starting":false},{"name":"A Safe Place","gist":"Preparing the party's camp site, hold 1 Precaution (2 if well-versed with the area). Spend 1 Precaution to reveal a prepared defense, warning, or trick; say how you knew.","level":1,"starting":false},{"name":"Magnificent Specimen","gist":"(Requires Animal Companion) Each time you take this move, your companion gains 2 additional options of your choice.","level":1,"starting":false},{"name":"Big Game Hunter","gist":"When you strike at the weak spot of a large or huge creature, you deal +2 damage.","level":1,"starting":false},{"name":"Blot Out the Sun","gist":"When you Let Fly with a bow, deplete your ammunition (mark next ammo status) before rolling; choose 1: advantage on damage, or add the area tag (roll damage per target).","level":1,"starting":false},{"name":"Call the Shot","gist":"Taking time to line up the perfect shot, deal damage or roll +DEX: 10+ deal damage and pick 2, 7-9 deal damage and pick 1 (ignore armor/+1d4; stun/hobble/hinder; trip or drop; or do no harm).","level":1,"starting":false},{"name":"Predator","gist":"When you Seek Insight, add: 'Who/what here is the easiest prey?' and 'How is ___ weak or vulnerable?' Acting on either answer deals an extra 1d4 damage.","level":1,"starting":false},{"name":"Sniff Out Corruption","gist":"When you Seek Insight, you can ask 'What here stinks of the unnatural?' for free, even on a 6-.","level":1,"starting":false},{"name":"Survivalist","gist":"When you Forage, pick 1 extra choice (even on a 6-, pick 1) and add 'Find or fashion some useful item or supply (GM can veto)' to the options.","level":1,"starting":false},{"name":"Warden of the Wild","gist":"When you defeat a perversion of nature, ask the GM 2: Will it come back/how to stop it? Will its taint spread/how to contain it? What grisly bits to harvest? What else to learn?","level":1,"starting":false},{"name":"Wild Speech","gist":"The grunts, barks, and calls of natural beasts are as a language to you; you understand intentions and communicate basic ideas. Persuade a beast with +WIS.","level":1,"starting":false},{"name":"Naturalist","gist":"When you Know Things about beasts, natural environs, or spirits of the wild, you have advantage.","level":1,"starting":false},{"name":"On the Hoof","gist":"Traveling the wilderness, procure 1d6 uses of provisions each day (disadvantage in winter or barren terrain). Provisions can substitute for supplies when you Make Camp.","level":1,"starting":false},{"name":"Pack Horse","gist":"You can carry up to 4 weight with a light load, 7 with a normal load, and 10 with a heavy load.","level":1,"starting":false},{"name":"Pathfinder","gist":"When you lead your people to Pull Together or Deploy beyond sight of home, you have advantage.","level":1,"starting":false},{"name":"Improved Stat","gist":"Each time you take this move, increase one of your stats by 1 (to a max of +2).","level":1,"starting":false},{"name":"Worldly","gist":"(Requires level 2+) Take a move from the Blessed, Fox, Heavy, Marshal, or Seeker playbooks you qualify for (different playbook each time). Not Improved/Superior Stat.","level":1,"starting":false},{"name":"Alpha","gist":"(Requires level 6+, and Wild Speech or Spirit Tongue) Asserting dominance over a beast/spirit/Fae/person, roll +WIS: 7+ they pick 1 (accept authority/slink away/fight you); 10+ also advantage next roll against them.","level":6,"starting":false},{"name":"Beast of Legend","gist":"(Requires level 6+ and Magnificent Specimen) Each time you take this move, pick 1: they're exceptional (roll +2 not +1); +4 HP and +1 armor; or develop a unique ability or trait.","level":6,"starting":false},{"name":"Constant Vigilance","gist":"(Requires level 6+) Unless dazed, you're never caught off guard, even asleep or on a 6-. Intercepting a sudden threat to you or an ally, you have advantage on whatever move you make.","level":6,"starting":false},{"name":"Giant Slayer","gist":"(Requires level 6+ and Big Game Hunter) When you strike at a weak spot of a large or huge creature, you deal another +2 damage (+4 total).","level":6,"starting":false},{"name":"Superior Stat","gist":"(Requires level 6+) Increase one of your stats by +1 (to a max of +3).","level":6,"starting":false},{"name":"Trailblazer","gist":"(Requires level 6+; replaces Home on the Range) When a journey makes you Defy Danger or Struggle as One, on a 10+ you also learn or discover something interesting and useful; ask the GM.","level":6,"starting":false},{"name":"Walk It Off","gist":"(Requires level 6+) When you'd mark a debility, mark this move instead to no ill effect. Clear it as you would a debility.","level":6,"starting":false}],"possessionsNote":"Composite bow, then pick 2:","possessions":[{"name":"Composite bow","gist":"Far, +1 damage, x piercing; low ammo, all out. (Fixed starting item.)"},{"name":"Distillery","gist":"Skins of fine whisky (uses; grants advantage to Persuade), copper tubes, malt, firkins, stills, barrels, etc."},{"name":"Hideouts (uses)","gist":"Expend a use to have a well-stocked, safe shelter nearby; GM can veto."},{"name":"Husbandry tools","gist":"Brushes, muzzles, collars, feed, whips, bridles, etc. Gain advantage to Persuade domestic beasts (livestock, dogs, etc.)."},{"name":"Hounds","gist":"2-3 followers (trackers, keen-nosed, fast); HP 6; Damage d6 (hand, grabby); Instinct to give chase; Cost: training."},{"name":"Lay of the land (uses)","gist":"Expend a use to know where to find ___, without having to Know Things; GM can veto."},{"name":"Trapping gear","gist":"Snares, pelts, musk, bait, etc. When you Forage, get +1 use of provisions."},{"name":"____ (discuss with GM)","gist":"An open option to define with the GM."}],"resources":[{"key":"precaution","name":"Precaution","max":2,"note":"From A Safe Place: hold 1 (or 2 if well-versed) when prepping a camp site."}],"followerInsert":{"type":"animalCompanion","note":"Tracks a bonded beast as a follower. Pick Type (Bird HP5/Arm1/d4, pick 4; Critter HP5/Arm1/d4, pick 5; Brute HP12/Arm0/d6, pick 3; Predator HP8/Arm0/d8, pick 3; Steed HP12/Arm0/d6+1, pick 4) with options/tags, plus Name, Instinct (pick 1), Cost/Loyalty (pick 1, max 3). Order Followers, Strengthen Your Bond, Loyal to the End. Beast of Legend upgrades."}},"seeker":{"key":"seeker","name":"The Seeker","page":133,"maxHp":16,"damageDie":"d6","baseArmor":0,"statArray":[2,1,1,0,0,-1],"instincts":["Cunning","Curiosity","Hubris","Mystery","Vision"],"backgrounds":[{"name":"Patriot","desc":"These people are family. You've sought out or been given dark power to protect what you hold dear, and you seek more.","grants":"Start with Let's Make a Deal; Well Versed in the Things Below. Acquire 1 major arcanum: Hec'tumel Codex, Red Scepter, or Staff of the Lidless Orb."},{"name":"Antiquarian","desc":"The past has buried many secrets and you dig them up. Years of study led you here, convinced this town holds the key to your greatest discoveries.","grants":"Start with Polyglot; Well Versed in the Makers and their arts. Acquire 1 major arcanum: Noruba's Ice Sphere, the Azure Hand, or the Mindgem."},{"name":"Witch Hunter","desc":"You've dedicated your life to rooting out and destroying horrors and their servants. What set you on this path, and what did you sacrifice?","grants":"Start with Everything Bleeds; Well Versed in (pick 1) the Fae, the Things Below, or the Last Door. Acquire 1 major arcanum: Demonhide Cloak, Redwood Effigy, or Twisted Spear."}],"startingNote":"You start with Well Versed, Work With What You've Got, plus 1 move from your chosen Background.","moves":[{"name":"Well Versed","gist":"Mark 1 topic beyond your Background's; when you Know Things about a topic, ask a free follow-up question even on a 6-.","level":1,"starting":true},{"name":"Work With What You've Got","gist":"When you cleverly use your environment to harm/impede foes, roll +INT: 10+ pick 2, 7-9 pick 1 (interrupt, create advantage, or deal damage).","level":1,"starting":true},{"name":"Let's Make a Deal","gist":"Seek Insight adds 'What do they really want or need?'; when you Persuade by offering what they want/need, treat 7-9 as 10+.","level":1,"starting":false},{"name":"Polyglot","gist":"Describe proficiency with each living language you first meet; Know Things about any script, text, runes or symbols with advantage.","level":1,"starting":false},{"name":"Everything Bleeds","gist":"When you exploit an unnatural foe's specific weakness or vulnerability, deal +1d6 damage.","level":1,"starting":false},{"name":"Attuned","gist":"When you Seek Insight you can always ask 'What here is infused with magic?' for free, even on a 6-.","level":1,"starting":false},{"name":"Conduit of Power","gist":"When you'd mark a Consequence from a major arcanum, mark 1 box here instead with no negative effect (these never clear).","level":1,"starting":false},{"name":"Countermeasures","gist":"When you witness a magical effect, ask how it can be countered/interrupted; you or an ally gain advantage to act on the answer.","level":1,"starting":false},{"name":"Everything Burns","gist":"Inspect a work of artifice/magic for a fatal flaw, roll +INT: 7+ GM reveals best way to destroy/sabotage it; 10+ also advantage to act.","level":1,"starting":false},{"name":"Quick Study","gist":"Study something magical in a fraction of the time: months become weeks, weeks become days, days become hours.","level":1,"starting":false},{"name":"Safety First","gist":"Spend an hour preparing mystical defenses to hold 2 Protection; spend 1 to gain advantage to resist harmful magic or halve its damage/effects.","level":1,"starting":false},{"name":"Sage Advice","gist":"When another PC asks you for guidance, they get advantage on their next roll to follow your advice.","level":1,"starting":false},{"name":"Logbook","gist":"Logbook (2 uses, slow, no inventory space); expend a use to treat a Know Things roll you just made as a 10+. Resets when Seasons Change.","level":1,"starting":false},{"name":"Magpie","gist":"When you Have What You Need, you can produce something strange/valuable/magical, but tell us where you got it and 2 complications.","level":1,"starting":false},{"name":"Never at a Loss","gist":"When you Know Things and roll a 6-, you may skip marking XP; instead the GM tells you nothing useful but how you could learn more.","level":1,"starting":false},{"name":"Cryptologist","gist":"Requires Polyglot. Study encoded/forgotten/arcane writing, roll +INT: 10+ fully decipher in minutes; 7-9 get the gist, full takes an hour.","level":1,"starting":false},{"name":"Initiate of the Secret Arts","gist":"Requires level 2+. Gain a Sacred Pouch (3 Stock, magical, no traits); each time, pick a Blessed move you qualify for (not Improved/Superior Stat).","level":1,"starting":false},{"name":"Improved Stat","gist":"Each time you take this move, increase one of your stats by 1 (to a max of +2).","level":1,"starting":false},{"name":"Arcane Adept","gist":"Requires level 6+. Detail a spell/effect and Make a Plan to invent it; you may swap one requirement for a GM-provided alternative.","level":6,"starting":false},{"name":"Deep Insight","gist":"Requires level 6+ and Attuned. When you Seek Insight about something magical, ask one extra question not limited to the list, even on a 6-.","level":6,"starting":false},{"name":"Improvise","gist":"Requires level 6+ and Quick Study. Use an unlocked arcanum move at a risk/consequence; roll +INT: 7+ works once; 10+ also mark progress to unlock.","level":6,"starting":false},{"name":"Superior Stat","gist":"Requires level 6+. Increase one of your stats by +1 (to a max of +3).","level":6,"starting":false},{"name":"Mind Over Magic","gist":"Requires level 6+. When you roll to study or use an arcanum, you can roll +INT instead of the stat you'd normally roll.","level":6,"starting":false},{"name":"Overchannel","gist":"Requires level 6+ and Conduit of Power. When you'd mark a Consequence from a major arcanum, you may mark a debility instead.","level":6,"starting":false},{"name":"Proof Against Detection","gist":"Requires level 6+ and Safety First. While you hold Protection you can't be scried/sensed magically and have advantage to Defy Danger stealthily.","level":6,"starting":false}],"possessionsNote":"Scribe's tools, then pick 2:","possessions":[{"name":"Scribe's tools","gist":"Parchment, ink, pigments, vials, quills, a notebook, etc. (fixed, always included)."},{"name":"Books & scrolls","gist":"Has uses; expend a use to consult your collection and turn a Know Things roll you just made into a 10+."},{"name":"Distillery","gist":"Skins of fine whisky (uses, grant advantage to Persuade), copper tubes, malt, firkins, stills, barrels, etc."},{"name":"Engineer's tools","gist":"Rulers, tapes, rods, plumb-bobs, tripods, block & tackles, wheelbarrow, etc."},{"name":"Laboratory","gist":"Chemics, reagents, vials, scales, decanters; each season produce d4-1 uses of naphtha (thrown, area, dangerous, ignores armor)."},{"name":"Paraphernalia","gist":"Crystals, incense, talismans, blood, bone, horn, eye of newt, braziers, a cauldron, etc."},{"name":"Trade contacts","gist":"Small amounts of salt, glass, silk, spice, medicinal herbs, pigments, ivory, etc. (discuss with GM)."}],"resources":[{"key":"protection","name":"Protection","max":2,"note":"From Safety First; spend 1 to resist/halve harmful magic. Only if you take Safety First."}],"arcana":[{"name":"The Hec'tumel Codex","gist":"Major arcanum offered by the Patriot background. Full rules in Book II."},{"name":"The Red Scepter","gist":"Major arcanum offered by the Patriot background. Full rules in Book II."},{"name":"The Staff of the Lidless Orb","gist":"Major arcanum offered by the Patriot background. Full rules in Book II."},{"name":"Noruba's Ice Sphere","gist":"Major arcanum offered by the Antiquarian background. Full rules in Book II."},{"name":"The Azure Hand","gist":"Major arcanum offered by the Antiquarian background. Full rules in Book II."},{"name":"The Mindgem","gist":"Major arcanum offered by the Antiquarian background. Full rules in Book II."},{"name":"The Demonhide Cloak","gist":"Major arcanum offered by the Witch Hunter background. Full rules in Book II."},{"name":"The Redwood Effigy","gist":"Major arcanum offered by the Witch Hunter background. Full rules in Book II."},{"name":"The Twisted Spear","gist":"Major arcanum offered by the Witch Hunter background. Full rules in Book II."}],"followerInsert":{"type":"none","note":""}},"hero":{"key":"hero","name":"The Would-Be Hero","page":137,"maxHp":16,"damageDie":"d6","baseArmor":0,"statArray":[1,0,0,0,0,-1],"instincts":["Defiance","Doubt","Earnestness","Optimism","Sacrifice"],"backgrounds":[{"name":"Impetuous Youth","desc":"Stonetop has always been home, but you chafe at mundane life and long for more. Excitement! Danger!","grants":"When you come up short, give it your all to bump a roll up one tier (6- to 7-9, etc.), but pick 1 cost: get hurt (2d4 + injury); collateral damage/escalation; something lost or broken."},{"name":"Driven","desc":"You once led a simple life, but something changed you and burdened you with terrible purpose. Choose 1 trigger event.","grants":"You can always Burn Brightly: spend 2 XP after you roll to add +1, even if you lack enough XP to level."},{"name":"Destined","desc":"Fate has laid her hand upon you. Choose 3-4 destiny descriptors. Until your destiny is fulfilled, treat a 6- on Death's Door as 7-9 and a 7-9 as 10+.","grants":"Grants the Omens resource: at session start roll +Omens for visions/portents; 6- holds +1 Omen and forfeits XP."}],"startingNote":"You start with Anger is a Gift and Potential for Greatness, plus 2 other moves of your choice.","moves":[{"name":"Anger is a Gift","gist":"When you burn with righteous anger, hold 2 Resolve; spend 1-for-1 to set aside fear, act suddenly, inspire allies, strike hard (+1d4 forceful), or keep footing.","level":1,"starting":true},{"name":"Potential for Greatness","gist":"Once per level, when you roll a stat and get 10+, mark one of 6 boons: +1 to that stat (max +2) x4, +4 max HP, or upgrade damage die to d8.","level":1,"starting":true},{"name":"Speak Truth to Power","gist":"Requires Anger is a Gift. When you demand someone do what is clearly good and right, you have advantage to Persuade. If they refuse, gain +1 Resolve.","level":1,"starting":false},{"name":"Better Part of Valor","gist":"When outnumbered or facing a foe bigger than you, you have advantage to hide from, escape from, or sneak past them.","level":1,"starting":false},{"name":"I Get Knocked Down","gist":"When you take damage despite your best efforts to avoid it, halve the damage but pick 1: lose something (footing, grip); something breaks; you're out of it a moment.","level":1,"starting":false},{"name":"But I Get Up Again","gist":"Requires I Get Knocked Down. When you use it, you have advantage on your next roll against whatever dealt the damage, and your next blow does +1d4 damage.","level":1,"starting":false},{"name":"Resourceful","gist":"When you Defy Danger and roll a 6-, ask the GM a Seek Insight question after they describe what happens. Gain advantage on your next roll to act on the answer.","level":1,"starting":false},{"name":"Something to Remember Me By","gist":"When you spend Readiness (from Defend) to strike back at an attacker, deal +1d4 damage and scar, mark, or diminish them somehow.","level":1,"starting":false},{"name":"Tough Love","gist":"When you honestly think another PC is in the wrong and call them on it, they have disadvantage on any rolls against you until you two work it out.","level":1,"starting":false},{"name":"Underestimated","gist":"As long as you avoid overt hostility, no enemy considers you a threat. When you first make your move against an enemy who underestimates you, you have advantage.","level":1,"starting":false},{"name":"Up With People","gist":"When you converse with someone, hold 2 Rapport; they hold 1 with you. Spend 1 Rapport to ask them an honest question (what holds you back, drives you, etc.).","level":1,"starting":false},{"name":"Improved Stat","gist":"Each time you take this move, increase one of your stats by 1, to a max of +2.","level":1,"starting":false},{"name":"In Over Your Head","gist":"When another PC rescues you from danger, mark XP.","level":1,"starting":false},{"name":"Iron Will","gist":"When subject to mind control or magic affecting your feelings, you can take 1d4 damage (ignoring armor) to disregard its influence.","level":1,"starting":false},{"name":"Inquiring Minds","gist":"When you seek out and receive honest advice, gain advantage on your next roll to follow that advice.","level":1,"starting":false},{"name":"Never Gonna Keep Me Down","gist":"When at 5 or fewer current HP, impose disadvantage on any damage you take. Once per session at Death's Door, don't roll; you get a 10+.","level":1,"starting":false},{"name":"Versatile","gist":"Requires level 2+, the Would-be Hero. Choose a move from any other playbook you qualify for (different one each time). Can't take Improved Stat or Superior Stat.","level":2,"starting":false},{"name":"Superior Stat","gist":"Requires all 6 marks in Potential for Greatness. Increase one of your stats by +1, to a max of +3.","level":6,"starting":false},{"name":"A Force to Be Reckoned With","gist":"Asterisked: crosses off 'Would-be'. Level 6+, replaces Underestimated. Creatures instinctively know you're a force; on Defy Danger 12+ vs harm/constraint, turn the tables.","level":6,"starting":false},{"name":"Big Damn Hero","gist":"Asterisked: crosses off 'Would-be'. Level 6+, replaces In Over Your Head. First leap to protect someone counts as 10+ Defend; spend 1 Readiness to lock eyes, giving attacker disadvantage on damage.","level":6,"starting":false},{"name":"Undaunted","gist":"Asterisked: crosses off 'Would-be'. Level 6+, replaces Better Part of Valor. When outnumbered or facing a bigger foe, you get +1 armor and deal +1d6 damage.","level":6,"starting":false},{"name":"Voice of Experience","gist":"Asterisked: crosses off 'Would-be'. Level 6+, replaces Inquiring Minds. PCs who follow your advice get advantage; when you Seek Insight you can always ask 'What is about to happen?' free, even on 6-.","level":6,"starting":false}],"possessionsNote":"Pick 2:","possessions":[{"name":"A heap of expectations","gist":"Of little use."},{"name":"A good dog (follower)","gist":"Retriever or herder, keen-nosed, clever; HP 6; Damage d6 (hand, grabby); Instinct to play; Cost: affection."},{"name":"Husbandry tools","gist":"Brushes, muzzles, collars, feed, whips, bridles, etc. Gain advantage to Persuade domestic beasts (livestock, dogs)."},{"name":"Smithy (or access to it)","gist":"Iron goods, ingots, thick gloves, tongs, bellows, an anvil, etc."},{"name":"Stoneworker's tools","gist":"Chisels, drills, prybars, spikes, block & tackles, wheelbarrow, etc."},{"name":"Personal token, fraught with meaning","gist":"Pick 1: shield with a crest; wool cloak woven for you; tear-and-blood-spattered letter; flute from a loved one; locket with a strand of hair; engraved tinder box."},{"name":"Tannery (or access to it)","gist":"Lime, acid, salts, thick gloves, a boiled leather cuirass (1 armor), etc."}],"resources":[{"key":"resolve","name":"Resolve","max":3,"note":"From Anger is a Gift; hold 2 when burning with righteous anger, spend 1-for-1."},{"key":"potential","name":"Potential for Greatness","max":6,"note":"6-box one-time level-up boons"},{"key":"omens","name":"Omens","max":6,"note":"Destined background only; roll +Omens at session start; hold +1 on a 6-."}],"followerInsert":{"type":"optional","note":"A good dog is a possible pick-2 possession granting a follower (HP 6, Damage d6 hand/grabby, Instinct to play)."}}};
window.STATES = {"ghost":{"name":"Ghost","page":148,"premise":"When you die but your soul lingers, refusing to pass through the Last Door, you gain this insert and choose 1 Consequence.","instincts":["Denial: To refuse to accept that you are dead.","Obsession: To pursue your Terrible Purpose no matter what.","Ennui: To bemoan your condition, to wish for release."],"choiceLabel":"Terrible Purpose","choices":[{"name":"Longing","gist":"Name those you won't let go of; watching them or earning their love heals/clears, rebuff marks consequence, their peaceful death frees you, violent loss marks the Final Consequence."},{"name":"Vengeance","gist":"Name those who must pay; raging heals, making one pay heals/clears, escape marks consequence, killing the last frees you, their early death marks the Final Consequence."},{"name":"Duty","gist":"Name the task you won't leave undone; working heals, milestones heal/clear, failure marks consequence, completion frees you, impossibility marks the Final Consequence."}],"moves":[{"name":"Unliving","gist":"You don't breathe, eat, drink, or sleep; you don't heal normally and gain no benefit from magical healing, Make Camp, Recover, or Convalesce."},{"name":"Disembodied","gist":"A spirit harmed only by silver, salt, or anti-spirit means; normally unseen, but can manifest (pick 1, lose 1d4 HP per extra: solid, speak, harmful touch) while concentrating."},{"name":"Tethered","gist":"Bound to remains, place, or object; at 0 HP mark a consequence and disperse, reforming near your tether at half max HP. Tether destroyed = mark the Final Consequence."}],"trackLabel":"Consequences","track":[{"name":"Bodysnatcher","gist":"Possess an unconscious/willing host (lose 1d4 HP) and control them; forcing abhorrent acts rolls +CHA; you share their damage and can keep a dead host alive."},{"name":"Breakdown","gist":"You lash out in an unthinking, unfeeling rage until next sunrise; ask the GM what snippets you remember."},{"name":"Unstable","gist":"Requires Breakdown. You're prone to rage episodes; when you roll a 6-, the GM can make you enter such a rage."},{"name":"Disturbing","gist":"Your presence chills the air and disturbs beasts and children; advantage when you Persuade via intimidation and your disturbing presence."},{"name":"Otherworldly","gist":"When you manifest a ghostly form, strange things happen: statues weep, rocks bleed, plants wither, water pools on ceilings, etc."},{"name":"Poltergeist","gist":"When angry, lose 1d4 HP for that much Fury; spend it to shatter objects, hurl objects (+DEX), or pin foes with telekinesis (+INT)."},{"name":"Quarry","gist":"The Pale Hunter has caught your scent. Expect a visit, soon."},{"name":"Specter","gist":"When you terrify a living person unconnected to your Terrible Purpose, regain 1d8 HP or clear a debility of your choice."},{"name":"The Final Consequence","gist":"Your tenuous connection to humanity is lost and you become a monster under the GM's control."}]},"revenant":{"name":"Revenant","page":150,"premise":"When you die but cling stubbornly to your body, refusing to pass through the Last Door, you gain this insert and choose 1 Consequence.","instincts":["Denial: To refuse to accept that you are dead.","Obsession: To pursue your Terrible Purpose no matter what.","Ennui: To bemoan your condition, to wish for release."],"choiceLabel":"Terrible Purpose","choices":[{"name":"Longing","gist":"Name those you won't let go of; watching them or earning their love heals/clears, rebuff marks consequence, their peaceful death frees you, violent loss marks the Final Consequence."},{"name":"Vengeance","gist":"Name those who must pay; raging heals, making one pay heals/clears, escape marks consequence, killing the last frees you, their early death marks the Final Consequence."},{"name":"Duty","gist":"Name the task you won't leave undone; working heals, milestones heal/clear, failure marks consequence, completion frees you, impossibility marks the Final Consequence."}],"moves":[{"name":"Unliving","gist":"You don't breathe, eat, drink, or sleep; you don't heal normally and gain no benefit from magical healing, Make Camp, Recover, or Convalesce."},{"name":"Undying","gist":"Immune to poison/disease, feel little pain, take half damage from physical attacks; at 0 HP roll +CON to regain half max HP and choose drawbacks (or become a Ghost). Body destroyed = treat as 0 HP, 6-."},{"name":"Implacable","gist":"Push your undead body: lose 1d4 HP and choose 1 - inhuman strength, uncanny speed/grace, or refuse to be moved, held, or knocked off course."}],"trackLabel":"Consequences","track":[{"name":"Breakdown","gist":"You lash out in an unthinking, unfeeling rage until next sunrise; ask the GM what snippets you remember."},{"name":"Unstable","gist":"Requires Breakdown. You're prone to rage episodes; when you roll a 6-, the GM can make you enter such a rage."},{"name":"Carrion Stench","gist":"A horrible odor follows you always; natural beasts and even predators shun you and your companions."},{"name":"Deathly Visage","gist":"It's clear to all that you are dead; advantage when you Persuade via intimidation and your sinister appearance."},{"name":"Home to Vermin","gist":"Bugs and vermin live in your corpse and do favors if asked; treat as followers (group, tiny, gross, meek, stealthy; HP 1; Cost: genuine affection)."},{"name":"Nightkin","gist":"You see in absolute darkness (black, white, red only); sunlight blinds you and direct sunlight burns your skin."},{"name":"Quarry","gist":"The Pale Hunter has caught your scent. Expect a visit, soon."},{"name":"Strange Appetites","gist":"Pick 1 (warm blood, dying breaths, brains, bone & marrow, rotting meat, eyes); consuming your special fare heals half max HP or clears a debility."},{"name":"Insatiable","gist":"Requires Strange Appetites. Opportunity to indulge grants advantage on your next roll if you do, or Defy Danger (vs. your own desires) if you don't."},{"name":"The Final Consequence","gist":"Your tenuous connection to humanity is lost and you become a monster under the GM's control."}]},"thrall":{"name":"Thrall","page":152,"premise":"When you die but call on one of the Things Below by name and beseech them to intercede, they do; death is averted but you gain this insert and 1 Mark.","masterNote":"The Thing Below you called upon plucked your soul from the Last Door and hides you from the Pale Hunter. It owns you now. Name your master and any titles you know.","instincts":["Fascination: To explore your powers, your master, your new existence.","Resistance: To struggle against your master and cling to your humanity.","Shame: To hide and deny your true nature."],"choiceLabel":"Impulse","choices":[{"name":"Stoke conflict, confusion, distrust","gist":"Sow discord among others."},{"name":"Erode hope/faith/honor/self-image","gist":"Wear down others' convictions and sense of self."},{"name":"Hide/bury/smother things or ideas","gist":"Conceal or suppress things or ideas."},{"name":"Deprive others of what they need","gist":"Take away what others depend on."},{"name":"Inflict harm, cruelly and unnecessarily","gist":"Hurt others gratuitously."},{"name":"Desecrate/mutilate/ruin things of value","gist":"Defile or destroy what is valued."},{"name":"Shock/terrify/horrify others","gist":"Frighten and appall others."}],"moves":[{"name":"Favor","gist":"Favor starts at 0, max 3; at 3 Favor when you'd gain more, reset to 0 and either ask your master a question (advantage on next roll) or gain a chosen Mark (and lose access to one)."},{"name":"Urges","gist":"Acting on your impulse when compelled (or uncompelled if it causes trouble) gains 1 Favor; resisting a compel rolls +WIS with escalating costs on 7-9 and lost control on a 6-."},{"name":"Dark Succor","gist":"When dying or killed, your master saves you; you recover, then roll +Favor and choose drawbacks (new Mark, lose a Mark, or a task that pins Favor at 0). Reset Favor to 0."},{"name":"Unholy Vessel","gist":"When you'd gain a Mark but none are left, your humanity is utterly lost; you become a threat in the GM's control and must make a new character."}],"trackLabel":"Marks","track":[{"name":"A Festering Rot","gist":"Immune to poison, disease, caustics, and vermin bites; things near you rot and corrode. On doubles, something on your person is ruined (GM decides)."},{"name":"Child of the Deeps","gist":"Max HP -2; breathe water, immune to cold/pressure, scaly skin; daily bath needed or mark debility. Near water, spend 1 Favor for a tentacle follower."},{"name":"Death Mask","gist":"Find/craft a horrid mask; without it you have disadvantage on all rolls. Wearing it, undead accept you, and spend 1 Favor to fill the living with dread."},{"name":"Quicksilver Dreams","gist":"Max HP -2; when you Make Camp everyone with you suffers nightmares and disadvantage on their next roll. Spend 1 Favor to inflict false sensations on someone you see."},{"name":"Ravenous","gist":"Unending hunger; gain impulse 'Wantonly devour flesh,' consume extra provisions at Camp. Spend 1 Favor to make a held thing coveted or grow an all-devouring maw."},{"name":"Red Wrath","gist":"Max HP -2; disadvantage to resist compulsions to violence. Lash out (hand, close), spend 1-3 Favor and roll +Favor spent for heavy damage and to awe onlookers."},{"name":"Shadow's Cold Embrace","gist":"Max HP -2; no shadow or reflection; can't spend Favor in sun/holy light. Otherwise spend 1 Favor to go unnoticed, leave no trace, or pass off a lie as truth."},{"name":"Speak Truth, Whisper Secrets","gist":"Max HP -2; long tongue and jagged teeth. Spend 1 Favor to look someone in the eye and learn a desire, shame, fear, or worst memory; advantage when you use it against them."},{"name":"Torment's Blessing","gist":"Wounds heal at half rate, but you never Defy Danger from pain/blood loss. Speak a word of torment, spend 1-3 Favor and roll +Favor spent to deal pain and stun victims."}]}};
window.STEADING = {"name":"Stonetop","size":"village","population":"~150-350","stats":[{"key":"surplus","name":"Surplus","start":1,"min":0,"max":null,"note":"Stored food/goods. Starts at 1; spent on improvements and consumed each winter."},{"key":"fortunes","name":"Fortunes","start":1,"min":-1,"max":3,"note":"Village luck/morale. Starts at +1. Range -1 +0 +1 +2 +3."},{"key":"population","name":"Population","start":0,"min":-1,"max":3,"note":"Number of people. Starts at +0. Range -1 +0 +1 +2 +3."},{"key":"prosperity","name":"Prosperity","start":0,"min":-1,"max":3,"note":"Wealth/quality of life. Starts at +0. Range -1 +0 +1 +2 +3."},{"key":"defenses","name":"Defenses","start":0,"min":-1,"max":3,"note":"Martial strength: -1 feeble, +0 mediocre, +1 strong, +2 formidable, +3 legendary."}],"debilitiesNote":"Steading debilities mark the village as compromised: diminished, lacking, or malcontent. Each imposes a penalty until cleared.","debilities":[{"name":"Diminished","gist":"From injury/sickness/doubt; disadvantage to Deploy, Muster, or Pull Together."},{"name":"Lacking","gist":"From shortages/hoarding/distrust; treat Prosperity as 1 lower than it is."},{"name":"Malcontent","gist":"From fear/anger/despair; Fortunes resets to +0 each season (not +1); folks need more Persuading."}],"defensesNote":"Defenses rates martial readiness from -1 feeble to +3 legendary, starting +0. Rolled to resist threats and during the aurochs hunt.","places":[{"name":"The Stone","note":"Ancient standing stone; central landmark of Stonetop."},{"name":"The Granary","note":"Stores the village's harvested Surplus."},{"name":"Public House & Stables","note":"Common room, lodging, and shelter for a few horses."},{"name":"Cistern","note":"Reservoir filled with rain and snow."},{"name":"Pavilion of the Gods","note":"Place of worship for the village."},{"name":"Watchtowers","note":"Three watchtowers along the Ringwall."}],"improvements":[{"name":"Additional Housing","gist":"Build more homes; increase Fortunes by 1. Henceforth treat Population as 1 lower when consuming Surplus in winter.","cost":"Roomier-house engineer OR build on fields (-1 Surplus/harvest); then Pull Together x5 (each 1 season, 1 Surplus, timber Value 2)."},{"name":"Aurochs Hunting","gist":"Add aurochs hunting to Resources. Each spring lead the hunt rolling +Defenses for 1d4 Surplus, with risks (lamed horses, injuries, offended Hillfolk) on lower rolls.","cost":"2 of: Herd of Horses, cooperating Hillfolk, a cunning plan; then a successful first hunt."},{"name":"Expanded Trades","gist":"Increase Prosperity by 1 (decrease if requirements lapse). Supports more specialized tradesfolk.","cost":"One of Harnessing the Stream / Raincatching / Mill, plus 3+ exceptional tradesfolk with tools (Value 2-3 each)."},{"name":"Greater Harvest","gist":"Increase Fortunes by 1. Henceforth gain +1d4 Surplus when the autumn harvest is complete.","cost":"1 of: double yield inside the Old Wall, or clear/tame new fields beyond it."},{"name":"Harnessing the Stream","gist":"Add to Resources, increase Fortunes by 1. Henceforth on a 7+ Fortunes roll at spring, generate 1 Surplus.","cost":"2 of: way to move water uphill, aqueducts from source, a reservoir."},{"name":"Herd of Horses","gist":"Increase Fortunes by 1; replace draft horses with a herd. Cheaper/faster Pull Together; herd breeds in summer and consumes Surplus in winter.","cost":"Stable & corral site, Pull Together to build (month, timber Value 2), trainer, ~dozen horses, training, tack (Value 2), riders trained (season, 1 Surplus), full-time handler."},{"name":"Heroic Reputation","gist":"Gain a move: when first meeting outsiders, roll +Fortunes to learn what they've heard about Stonetop and gain advantage.","cost":"Any 3 of: impress Hillfolk, brave a lake, save many in Marshedge or Gordin's Delve, save someone from beyond, hire a minstrel (Value 2)."},{"name":"Inn","gist":"Increase Fortunes by 1; add to Resources & map. Seasons change: roll +Fortunes to ask GM questions. Once/season spend 1 Surplus to gather folks and clear a debility.","cost":"All in order: building site, engineer/foreman, furnishings (Value 3), Pull Together x2 (each 1 season, 1 Surplus, supplies Value 2), devoted staff."},{"name":"Market","gist":"Increase Prosperity by 1 (decrease if lapses). Generates 1 Surplus each spring/summer/autumn when active and Population is +1 or better.","cost":"1 of: exclusive good/service or reason to visit; plus market site, trusted arbiter, 4 seasons without notable violence/banditry/theft."},{"name":"Mill","gist":"Increase Fortunes by 1; add to Resources & map. Generate +1 Surplus at autumn harvest; Outfit supplies get 1 extra use.","cost":"All: exceptional engineer/foreman, consistent power source, suitable site, Pull Together x2 (each season, 1 Surplus, timber Value 2, rope/supplies Value 2), full-time miller."},{"name":"Palisade","gist":"10' wall of sharpened logs. Increase Fortunes by 1; add to Fortifications & map. Advantage to Deploy when taking advantage of it.","cost":"All in order: ~20-25 wagonloads timber (Value 3), competent engineer/foreman, rope/nails/pitch (Value 2), Pull Together (month, 1 Surplus)."},{"name":"Raincatching","gist":"Add to Resources, increase Fortunes by 1. Henceforth on a 7+ Fortunes roll in summer, generate 1 Surplus.","cost":"All in order: exceptional engineer/foreman, slate/terracotta to roof buildings and build gutters (Value 3), Pull Together x3 (each 1 season, 1 Surplus)."},{"name":"Standing Watch","gist":"Add standing watch to Fortifications; consumes 1 Surplus each season or disbands. Involving the watch treats Defenses as 1 higher.","cost":"All: veteran warrior commander, 6+ well-equipped willing warriors, village leaders agreeing to support full-time watch."},{"name":"Stone Wall","gist":"Mighty rampart (erase Palisade). Advantage to Deploy when used; consumes 1 less Surplus than normal each winter.","cost":"All in order: exceptional engineer/foreman, stonecutter with crew, equipment/material (Value 3), Pull Together x4 (each 1 season, 1 Surplus, supplies Value 2)."},{"name":"Township","gist":"Change Size to town and Population to +0. Advantage to Muster/Pull Together/Trade & Barter; bigger Surplus swings each season.","cost":"All: Population +3 for 4 seasons, Additional Housing, Raincatching or Diverting the Stream, 4+ other improvements, a formal government."},{"name":"Weapons of War","gist":"Increase Defenses by 1; add to Fortifications (1 Surplus/spring upkeep). Treat advanced weapons as common items; swords/axes gain piercing equal to Prosperity.","cost":"Acquire dozens of good weapons (Value 3) OR smith+staff (Value 2), iron ore (Value 2), 4 seasons of work; then veteran warrior and Pull Together (season, 1 Surplus)."},{"name":"Well-Trained Militia","gist":"Drill tactics (archery, cavalry, formations, readiness, skirmishing). Deploy from strength; 2+ tactics increase Defenses by 1; upkeep each summer.","cost":"Veteran warrior commander; then Pull Together per tactic (each a season of drills and 1 Surplus)."}],"assets":[{"name":"A pair of hardy draft horses","gist":"Followers (large, powerful, keen-nosed, hardy): HP 10 each; Damage d6+3 (hand, close, forceful); Instinct to panic; Cost: care & grooming."},{"name":"A pair of horse-drawn plows","gist":"Iron plows for working the fields."},{"name":"A pair of carts","gist":"With horse harness, for hauling goods."},{"name":"A wagon","gist":"With horse harness, for larger loads of supplies."}],"treasuryNote":"Silver and Gold each tracked separately in Purses, Handfuls, and Coins."};
